function work_from_home_tasks_app_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('work_from_home_tasks_app');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	// automatic work_from_home_details if passed as filterer
	if(Request::val('filterer_work_from_home_details')) {
		$_REQUEST['work_from_home_details'] = Request::val('filterer_work_from_home_details');
	}

	$data = [
		'approval_from' => Request::val('approval_from', 'CEO'),
		'day' => Request::dateComponents('day', ''),
		'hour_from' => Request::val('hour_from', ''),
		'hour_to' => Request::val('hour_to', ''),
		'activity_undertaken' => Request::val('activity_undertaken', ''),
		'approval_status' => Request::val('approval_status', 'Under Consideration'),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];


	// automatic work_from_home_details if passed as filterer
	if(Request::val('filterer_work_from_home_details')) {
		$data['work_from_home_details'] = Request::val('filterer_work_from_home_details');
	}
	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('work_from_home_tasks_app', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		work_from_home_tasks_app_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function work_from_home_tasks_app_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
