	// launch requests, asynchronously
	curl_batch($requests);
}

function work_from_home_tasks_app_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('work_from_home_tasks_app', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: work_from_home_tasks_app_before_delete
	if(function_exists('work_from_home_tasks_app_before_delete')) {
		$args = [];
		if(!work_from_home_tasks_app_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `work_from_home_tasks_app` WHERE `id`='{$selected_id}'", $eo);

	// hook: work_from_home_tasks_app_after_delete
	if(function_exists('work_from_home_tasks_app_after_delete')) {
		$args = [];
		work_from_home_tasks_app_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='work_from_home_tasks_app' AND `pkValue`='{$selected_id}'", $eo);
}

function work_from_home_tasks_app_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('work_from_home_tasks_app', $selected_id, 'edit')) return false;

	$data = [
		'approval_from' => Request::val('approval_from', ''),
		'day' => Request::dateComponents('day', ''),
		'hour_from' => Request::val('hour_from', ''),
		'hour_to' => Request::val('hour_to', ''),
		'activity_undertaken' => Request::val('activity_undertaken', ''),
		'approval_status' => Request::val('approval_status', ''),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	// get existing values
	$old_data = getRecord('work_from_home_tasks_app', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: work_from_home_tasks_app_before_update
	if(function_exists('work_from_home_tasks_app_before_update')) {
		$args = ['old_data' => $old_data];
		if(!work_from_home_tasks_app_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'work_from_home_tasks_app',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="work_from_home_tasks_app_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('work_from_home_tasks_app', $data['selectedID'], calculated_fields()['work_from_home_tasks_app']);

	// hook: work_from_home_tasks_app_after_update
	if(function_exists('work_from_home_tasks_app_after_update')) {
		if($row = getRecord('work_from_home_tasks_app', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!work_from_home_tasks_app_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('work_from_home_tasks_app', $selected_id);
}

